import{c as t,Q as o,j as n,m as a}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md","lastUpdated":1778862269000}'),s={name:"guide/introduction.md"};function r(i,e,l,c,d,h){return o(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>Exto Console is the central control plane for the Exto platform. It unifies the work that, in most B2B SaaS companies, is scattered across spreadsheets, ticketing systems, and side scripts — managing customers, provisioning tenant environments, controlling identity, orchestrating releases, and billing accurately for usage.</p><h2 id="what-the-console-does" tabindex="-1">What the Console does <a class="header-anchor" href="#what-the-console-does" aria-label="Permalink to &quot;What the Console does&quot;">​</a></h2><p>The Console is built around four pillars:</p><ol><li><p><strong>Universal Identity &amp; Access.</strong> A single sign-on experience for every Exto application. The Console binds users to the customers, tenants, and instances they are entitled to use, and enforces multi-factor authentication, password policy, and identity-provider rules for each customer organisation.</p></li><li><p><strong>Customer, Tenant &amp; Instance Management.</strong> Customers represent the companies you sell to. Each customer owns one or more tenants — isolated logical environments inside a hosted instance. The Console handles the entire lifecycle: create, configure, suspend, archive, move between customers, or migrate to a different instance.</p></li><li><p><strong>Release Orchestration.</strong> Define a deployment pipeline once, then ship every release through it. Releases bundle service images and environment-variable changes, run through stages with approval and trigger gates, and produce a verifiable audit trail.</p></li><li><p><strong>Metering &amp; Billing.</strong> Define meters for the things you charge for. Bind them to plans, assign plans to customers, and let the Console compute billed usage automatically — with first-class support for production vs. non-production environments, per-tenant overrides, and overage pricing.</p></li></ol><h2 id="two-surfaces-two-audiences" tabindex="-1">Two surfaces, two audiences <a class="header-anchor" href="#two-surfaces-two-audiences" aria-label="Permalink to &quot;Two surfaces, two audiences&quot;">​</a></h2><p>The Console exposes two distinct workspaces:</p><ul><li><p>The <strong>Admin Console</strong> is for Exto operators — infrastructure ops, account managers, QA admins, and platform admins. It exposes everything the platform can do: every customer, every tenant, every instance, every release.</p></li><li><p>The <strong>Customer Portal</strong> is what your customers see when they log in. It is scoped to a single customer, hides operator-only functionality, and is gated by portal roles (owner, admin, member).</p></li></ul><p>Both surfaces share the same identity layer, the same release machinery, and the same billing engine — they just present different slices of it.</p><h2 id="how-to-use-this-guide" tabindex="-1">How to use this guide <a class="header-anchor" href="#how-to-use-this-guide" aria-label="Permalink to &quot;How to use this guide&quot;">​</a></h2><p>If you are an Exto operator, start with <a href="./getting-started">Quick Start</a> and then jump into <a href="./admin/">the Admin Console section</a>.</p><p>If you are a customer admin signing in for the first time, read <a href="./account/signing-in">Signing In</a> and the <a href="./portal/">Customer Portal Overview</a>.</p><p>If you want to understand how the pieces fit together before opening the UI, read <a href="./concepts/architecture">Core Concepts</a> end-to-end. Everything else in the guide refers back to those concepts.</p>',13)])])}const g=t(s,[["render",r]]);export{p as __pageData,g as default};
